diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..c7f7fa6e7345 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7765,11 +7765,79 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
   return new FCmpInst(Pred, LHSI->getOperand(1), RHSC, "", &I);
 }

-/// Optimize fabs(X) compared with zero.
+/// Try to match the pattern select (fcmp pred X, 0), X, fneg X
+/// which computes a sign-independent operation. Returns the inner value X 
+/// if matched, nullptr otherwise.
+/// For equality predicates (oeq, ueq, one, une), also matches select with
+/// arbitrary condition since sign doesn't affect equality comparison with zero.
+static Value *matchSelectOfFNegToFabs(SelectInst *SI, FCmpInst::Predicate OuterPred) {
+  Value *CondVal = SI->getCondition();
+  Value *TrueVal = SI->getTrueValue();
+  Value *FalseVal = SI->getFalseValue();
+  Value *X;
+  CmpInst::Predicate Pred;
+
+  // Match: select (fcmp oge/ogt X, 0), X, fneg X  -> fabs pattern
+  if (match(CondVal, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())) &&
+      match(TrueVal, m_Specific(X)) &&
+      match(FalseVal, m_FNeg(m_Specific(X)))) {
+    if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
+        Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_UGT)
+      return X;
+  }
+
+  // Match: select (fcmp olt/ole X, 0), fneg X, X  -> fabs pattern (swapped)
+  if (match(CondVal, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())) &&
+      match(TrueVal, m_FNeg(m_Specific(X))) &&
+      match(FalseVal, m_Specific(X))) {
+    if (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
+        Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE)
+      return X;
+  }
+
+  // Match: select (fcmp oeq/ueq/one/une X, 0), X, fneg X with same predicate
+  if (match(CondVal, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())) &&
+      match(TrueVal, m_Specific(X)) &&
+      match(FalseVal, m_FNeg(m_Specific(X)))) {
+    if (Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UEQ ||
+        Pred == FCmpInst::FCMP_ONE || Pred == FCmpInst::FCMP_UNE)
+      return X;
+  }
+
+  // Same for swapped: select (fcmp oeq/ueq/one/une X, 0), fneg X, X
+  if (match(CondVal, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())) &&
+      match(TrueVal, m_FNeg(m_Specific(X))) &&
+      match(FalseVal, m_Specific(X))) {
+    if (Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UEQ ||
+        Pred == FCmpInst::FCMP_ONE || Pred == FCmpInst::FCMP_UNE)
+      return X;
+  }
+
+  // For equality predicates, any select with X and fneg(X) works
+  // because sign doesn't affect equality comparison with zero
+  if (OuterPred == FCmpInst::FCMP_OEQ || OuterPred == FCmpInst::FCMP_UEQ ||
+      OuterPred == FCmpInst::FCMP_ONE || OuterPred == FCmpInst::FCMP_UNE) {
+    if (match(TrueVal, m_Value(X)) && match(FalseVal, m_FNeg(m_Specific(X))))
+      return X;
+    if (match(TrueVal, m_FNeg(m_Value(X))) && match(FalseVal, m_Specific(X)))
+      return X;
+  }
+
+  return nullptr;
+}
+
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
+  // First try to match the fabs intrinsic
+  if (match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // X is already extracted
+  } else if (SelectInst *SI = dyn_cast<SelectInst>(I.getOperand(0))) {
+    // Try to match select pattern
+    if (!(X = matchSelectOfFNegToFabs(SI, I.getPredicate())))
+      return nullptr;
+  } else {
     return nullptr;
+  }

   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))

